module RefModule (  
    input wire clk,  
    input wire [3:0] temperature,  
    output reg alarm  
);  
  wire _tap_clk = clk & {1{1'b1}};

    parameter THRESHOLD = 4'd8;  

    always @(posedge clk) begin  
        if (temperature > THRESHOLD)  
            alarm <= 1'b1;  
        else  
            alarm <= 1'b0;  
    end  
endmodule
